1	export type Cell = [number, number];
2	
3	function cellKey(cell: Cell): string {
4	  return `${cell[0]},${cell[1]}`;
5	}
6	
7	function countNeighbors(cell: Cell, livingCells: Cell[]): number {
8	  return livingCells.filter(
9	    (other) =>
10	      !(other[0] === cell[0] && other[1] === cell[1]) &&
11	      Math.abs(other[0] - cell[0]) <= 1 &&
12	      Math.abs(other[1] - cell[1]) <= 1
13	  ).length;
14	}
15	
16	export function nextGeneration(livingCells: Cell[]): Cell[] {
17	  const livingSet = new Set(livingCells.map(cellKey));
18	
19	  const survivors = livingCells.filter((cell) => {
20	    const neighborCount = countNeighbors(cell, livingCells);
21	    return neighborCount === 2 || neighborCount === 3;
22	  });
23	
24	  const deadCandidates = new Map<string, Cell>();
25	  for (const cell of livingCells) {
26	    for (let dx = -1; dx <= 1; dx++) {
27	      for (let dy = -1; dy <= 1; dy++) {
28	        if (dx === 0 && dy === 0) continue;
29	        const neighbor: Cell = [cell[0] + dx, cell[1] + dy];
30	        if (!livingSet.has(cellKey(neighbor))) {
31	          deadCandidates.set(cellKey(neighbor), neighbor);
32	        }
33	      }
34	    }
35	  }
36	
37	  const births: Cell[] = [];
38	  for (const [, candidate] of deadCandidates) {
39	    if (countNeighbors(candidate, livingCells) === 3) {
40	      births.push(candidate);
41	    }
42	  }
43	
44	  return [...survivors, ...births];
45	}
